"use client";

import { useState } from "react";

export default function OrderTab({ orders }) {
    const [orderList, setOrderList] = useState(orders);

    const handleReceive = (id) => {
        setOrderList(prev => prev.filter(order => order.id !== id));
    };

    return (
        <div className="space-y-6">
            {orderList.length > 0 ? (
                orderList.map(order => (
                    <div
                        key={order.id}
                        className="flex items-start space-x-4 pb-4 border-b"
                    >
                        {/* รูปสินค้า */}
                        <img
                            src={order.image}
                            alt={order.name}
                            className="w-16 h-16 border rounded object-cover"
                        />

                        {/* รายละเอียดสินค้า */}
                        <div className="flex-1">
                            <p className="text-sm font-medium">{order.name}</p>
                            <p className="text-xs text-gray-500">
                                TotalProduct: {order.qty}
                            </p>
                            <p className="text-xs mt-1">
                                Status:{" "}
                                <span
                                    className={`font-medium ${
                                        order.status === "pending"
                                            ? "text-green-600"
                                            : "text-orange-500"
                                    }`}
                                >
                                    {order.status}
                                </span>
                            </p>
                        </div>

                        {/* ราคา + ปุ่ม */}
                        <div className="flex flex-col items-end justify-between">
                            <span className="font-semibold">
                                ${order.price}
                            </span>
                            {order.status === "fulfilled" ? (
                                <button
                                    onClick={() => handleReceive(order.id)}
                                    className="mt-2 px-3 py-1 text-xs bg-green-600 text-white rounded"
                                >
                                    receive
                                </button>
                            ) : (
                                <button className="mt-2 px-3 py-1 text-xs bg-gray-200 rounded cursor-not-allowed">
                                    receive
                                </button>
                            )}
                        </div>
                    </div>
                ))
            ) : (
                <div className="text-center text-gray-500 mt-10">
                    📦 No orders yet.
                </div>
            )}
        </div>
    );
}
